// Generate site/public/home.md — the markdown representation of the
// landing page that the middleware serves when a client hits `/` with
// `Accept: text/markdown`.
//
// Reads from:
//   - src/data/categories.json       (shared with (home)/page.tsx)
//   - src/data/recent-updates.json   (generated by recent-updates.mjs)
//   - ../guides/*.md                 (guide frontmatter titles)
//   - ../case-studies/*.md           (case study frontmatter titles)
//
// Run as part of site/package.json's prebuild script, AFTER
// recent-updates.mjs (home.md depends on recent-updates.json).

import { readdir, readFile, writeFile } from 'node:fs/promises';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const scriptDir = dirname(fileURLToPath(import.meta.url));
const siteDir = resolve(scriptDir, '..');
const repoRoot = resolve(siteDir, '..');

const SITE_URL = 'https://claude-almanac.sivura.com';
const TAGLINE =
  'A knowledge base for humans and AI agents — Claude Code features, configurations, and workflows.';
const AUTHOR = 'By Alexander Sivura.';

function parseFrontmatterTitle(text, fallback) {
  // Minimal frontmatter parser — reads `title:` from the top YAML block.
  // Supports both `title: Foo` and `title: "Foo"` / `title: 'Foo'`.
  const match = text.match(/^---\s*\n([\s\S]*?)\n---/);
  if (!match) return fallback;
  const titleLine = match[1]
    .split('\n')
    .find((line) => /^title:/.test(line.trim()));
  if (!titleLine) return fallback;
  return titleLine
    .replace(/^title:\s*/, '')
    .trim()
    .replace(/^['"]|['"]$/g, '');
}

async function listMarkdown(dir) {
  try {
    const entries = await readdir(dir);
    // README.md in guides/ and case-studies/ is collection chrome,
    // not content — skip it.
    return entries.filter(
      (name) => name.endsWith('.md') && name !== 'README.md',
    );
  } catch {
    return [];
  }
}

async function collectCollection(collectionDir) {
  const dir = resolve(repoRoot, collectionDir);
  const files = await listMarkdown(dir);
  const results = [];
  for (const file of files) {
    const slug = file.replace(/\.md$/, '');
    const content = await readFile(resolve(dir, file), 'utf8');
    const title = parseFrontmatterTitle(content, slug);
    results.push({ slug, title });
  }
  results.sort((a, b) => a.title.localeCompare(b.title));
  return results;
}

async function main() {
  const categoriesPath = resolve(siteDir, 'src/data/categories.json');
  const recentPath = resolve(siteDir, 'src/data/recent-updates.json');

  const categories = JSON.parse(await readFile(categoriesPath, 'utf8'));
  let recent = [];
  try {
    recent = JSON.parse(await readFile(recentPath, 'utf8'));
  } catch {
    // recent-updates.json not generated yet; home.md ships without the section.
  }

  const guides = await collectCollection('guides');
  const caseStudies = await collectCollection('case-studies');

  const lines = [];
  lines.push('# Claude Almanac');
  lines.push('');
  lines.push(TAGLINE);
  lines.push('');
  lines.push(AUTHOR);
  lines.push('');
  lines.push(`- **Browse docs**: ${SITE_URL}/docs`);
  lines.push('- **GitHub**: https://github.com/asivura/claude-almanac');
  lines.push('');
  lines.push('## Browse by category');
  lines.push('');
  for (const cat of categories) {
    lines.push(
      `- **${cat.title}** — ${cat.description} Start at [${cat.href}](${cat.href})`,
    );
  }
  lines.push('');
  if (guides.length > 0) {
    lines.push('## Guides');
    lines.push('');
    for (const g of guides) {
      lines.push(`- [${g.title}](/docs/${g.slug})`);
    }
    lines.push('');
  }
  if (caseStudies.length > 0) {
    lines.push('## Case studies');
    lines.push('');
    for (const c of caseStudies) {
      lines.push(`- [${c.title}](/docs/${c.slug})`);
    }
    lines.push('');
  }
  if (recent.length > 0) {
    lines.push('## Recent updates');
    lines.push('');
    for (const r of recent) {
      lines.push(`- ${r.date} · ${r.subject}`);
    }
    lines.push('');
  }
  lines.push('## For agents');
  lines.push('');
  lines.push('- `/llms.txt` — full index with links');
  lines.push('- `/llms-full.txt` — all content concatenated');
  lines.push(
    '- `Accept: text/markdown` on any `/docs/*` URL returns markdown',
  );
  lines.push(
    '- Per-page markdown at `/llms.mdx/docs/<slug>/content.md`',
  );
  lines.push('');

  const output = lines.join('\n');
  const outPath = resolve(siteDir, 'public/home.md');
  await writeFile(outPath, output, 'utf8');
  console.log(`[home-markdown] wrote ${output.length} bytes → public/home.md`);
}

main().catch((err) => {
  console.error('[home-markdown] failed:', err);
  process.exit(1);
});
